/**
 * Pre-build script: reads nssm.exe and generates nssm-bundle.js
 * as a CommonJS module exporting the binary as a base64-encoded Buffer.
 *
 * This avoids relying on pkg's `assets` config (which is unreliable in v5.8.1)
 * by bundling nssm.exe as plain JavaScript that pkg handles naturally.
 */
'use strict';
const fs = require('fs');
const path = require('path');

const nssmSrc = path.join(__dirname, '..', 'nssm', 'nssm.exe');
const outFile = path.join(__dirname, '..', 'nssm-bundle.js');

if (!fs.existsSync(nssmSrc)) {
  console.error('[bundle-nssm] ERROR: nssm.exe not found at', nssmSrc);
  process.exit(1);
}

const data = fs.readFileSync(nssmSrc);
const base64 = data.toString('base64');

const output = `// Auto-generated by scripts/bundle-nssm.js — do not edit manually
'use strict';
module.exports = Buffer.from('${base64}', 'base64');
`;

fs.writeFileSync(outFile, output);
console.log('[bundle-nssm] ✓ nssm-bundle.js generated (' + (Buffer.byteLength(output) / 1024).toFixed(0) + ' KB)');
